INSERT INTO protocols (id, code, name, description, selection_policy, min_tier_required, duration_days, weights_json, is_active, created_at, updated_at) VALUES (1, 'P_MILD_21', 'Phác đồ Nhẹ (21 ngày)', 'Mức Độ NHẸ — Chương Trình Khởi Động 21 Ngày. Thích hợp cho người dùng điện thoại thông minh ở mức độ chớm lệ thuộc.', 'USER_SELECT', 'BASIC', 21, '{"severity":0.3,"motivation":0.3,"adherenceRisk":0.2,"lifestyleConstraint":0.2}', TRUE, NOW(), NOW());
INSERT INTO protocols (id, code, name, description, selection_policy, min_tier_required, duration_days, weights_json, is_active, created_at, updated_at) VALUES (2, 'P_MODERATE_45', 'Phác đồ Trung bình (45 ngày)', 'Mức Độ TRUNG BÌNH — Chương Trình 45 Ngày. Dành cho người mất kiểm soát thời gian sử dụng, bồn chồn nhẹ khi thiếu điện thoại.', 'USER_SELECT', 'BASIC', 45, '{"severity":0.4,"motivation":0.2,"adherenceRisk":0.2,"lifestyleConstraint":0.2}', TRUE, NOW(), NOW());
INSERT INTO protocols (id, code, name, description, selection_policy, min_tier_required, duration_days, weights_json, is_active, created_at, updated_at) VALUES (3, 'P_SEVERE_90', 'Phác đồ Nặng (90 ngày)', 'Mức Độ NẶNG — Chương Trình Chuyên Sâu 90 Ngày. Phù hợp cho người bị ảnh hưởng rõ rệt tới giấc ngủ, hiệu suất và quan hệ xã hội.', 'USER_SELECT', 'BASIC', 90, '{"severity":0.5,"motivation":0.1,"adherenceRisk":0.3,"lifestyleConstraint":0.1}', TRUE, NOW(), NOW());
INSERT INTO protocols (id, code, name, description, selection_policy, min_tier_required, duration_days, weights_json, is_active, created_at, updated_at) VALUES (4, 'P_INTENSIVE_120', 'Phác đồ Chuyên sâu (120 ngày)', 'Chương Trình 120 Ngày Dựa Trên Bằng Chứng Khoa Học. Cai nghiện dopamine toàn diện từ internet, khôi phục khả năng kiểm soát xung động.', 'USER_SELECT', 'BASIC', 120, '{"severity":0.5,"motivation":0.1,"adherenceRisk":0.2,"lifestyleConstraint":0.2}', TRUE, NOW(), NOW());
