INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (8, 4, 1, 'Thanh lọc và nhận thức', 'Ngày 1–30', '🧠', 'Ngắt kết nối, đo chỉ số nền tảng, kiểm soát kích thích và thiết lập ranh giới môi trường.', 'Tăng nhạy cảm thụ thể dopamine (Nestler, 2004); kiểm soát kích thích (Koob và Volkow, 2016).');
INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (9, 4, 2, 'Củng cố nền tảng', 'Ngày 31–60', '⚡', 'Xây dựng thói quen thay thế, nâng cao khả năng chống chịu cảm xúc khó chịu và tái thiết lập quan hệ xã hội.', 'Hình thành thói quen (Lally et al., 2010); Củng cố hành vi dựa trên chánh niệm (Garland et al., 2017).');
INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (10, 4, 3, 'Tích hợp vào cuộc sống', 'Ngày 61–90', '🌱', 'Phát triển bản sắc mới, ứng dụng sáng tạo ngoại tuyến và tối ưu hóa sức khỏe thể chất.', 'Lý thuyết tự quyết (Deci và Ryan, 2000); củng cố thói quen dựa trên bản sắc (Clear, 2018).');
